mapper.select:
SELECT 
FROM resume_upload_record
WHERE user_id = #{userId}
AND user_shard = #{userShard}
ORDER BY last_update_time DESC

mapper.insert:
INSERT INTO resume_upload_record (
    record_id, bucket_name, object_key, local_file_path, file_size, part_size,
    total_part_count, uploaded_parts, upload_status, user_id, user_shard, client_type,
    device_id, concurrent_threads, start_time, complete_time, last_update_time
) VALUES (
    #{recordId}, #{bucketName}, #{objectKey}, #{localFilePath}, #{fileSize}, #{partSize},
    #{totalPartCount}, #{uploadedParts}, #{uploadStatus}, #{userId}, #{userShard},
    #{clientType}, #{deviceId}, #{concurrentThreads}, #{startTime}, #{completeTime},
    #{lastUpdateTime}
)

mapper.update:
UPDATE resume_upload_record
uploaded_parts = #{uploadedParts}, upload_status = #{uploadStatus}, complete_time = #{completeTime}, last_update_time = #{lastUpdateTime}, updated_time = NOW()
WHERE record_id = #{recordId}

mapper.delete:
DELETE FROM resume_upload_record
WHERE upload_status IN ('COMPLETED', 'FAILED', 'CANCELLED')
AND updated_time < #{expireTime}
